	.TITLE	EXSPLINE;	Daniel Roux	.PROC	M680002	.RADIX	10.	.HEX	.REF	SM8	.REF	NTREL	.REF	GESMEM	.REF	BIOS	.REF	FOS	.REF	LIB	.REF	DRIVERS	.REF	SPLINE	.CODE	500,11,B'111,20,2000,20,2000,2,'*,0,0; Variables en (A6); -----------------LBUFFER	=	500	.LOC	0OCHSPLINE:.BLKB	2		; canal module SPLINEOSTEP:	.BLKB	2		; pas de l'arrondiOBUFFER:.BLKB	LBUFFER		; buffer pour le texteLGVAR:; Dbut du code; -------------	.LOC	0START:	.W	LIB,?OPELIB	; ouvre la librairie ...	LOAD.W	D3,#2	.W	LIB,?MOUSE	; souris par le clavier	LOAD.L	D4,#LGVAR	; D4 <-- longueur ncessaire	LOAD.W	D1,#MTYPCP	; D1 <-- pour processus courant	.W	GESMEM,?GETMEM	; demande mmoire pour var	JUMP,NE ERFAT1		; plein => erreur fatale	LOAD.L	A6,A4		; A6 <-- ^variables (TOUJOURS)10$:	CLR.B	(A4+)		; rempli TOUTES les variables	DEC.W	D4		; avec des zro !	JUMP,NE	10$	LOAD.W	(A6)+OSTEP,#8	LOAD.L	A3,#R16"NAMSPLINE	LOAD.W	D3,#SPLINE_FIRST	.W	LIB_OPEN	; ouvre le module SPLINE	JUMP,NE	ERFAT2	LOAD.W	(A6)+OCHSPLINE,D1	.W	LIB,?AFTIM	.B	NOCURS	.ASCIZ	"[POINT]  [FERME]  [LIE]"	.EVENLOOP1:	LOAD.L	A3,#(A6)+OBUFFERLOOP:	.W	LIB,?GETCAR	COMP.W	D3,#END	JUMP,EQ	RETOUR	COMP.W	D3,#KEYMGP	JUMP,EQ	20$	COMP.W	D3,#KEYMMP	JUMP,EQ	30$	COMP.W	D3,#KEYMDP	JUMP,EQ	40$	COMP.W	D3,#UNDO	JUMP,EQ	60$	COMP.W	D3,#'1	JUMP,LO	10$	COMP.W	D3,#'9	JUMP,HI	10$	SUB.W	D3,#'0	LOAD.W	(A6)+OSTEP,D3	JUMP	LOOP10$:	LOAD.B	D3,#BIPLIT	.W	LIB,?BEEP	JUMP	LOOP20$:	.W	LIB,?IFMOUSE	LOAD.L	(A3+),D4	LOAD.L	D3,D4	LOAD.W	D4,#4	LOAD.W	D2,#SETDOT	.W	LIB,?DRCERCLE	JUMP	LOOP30$:	LOAD.L	(A3+),(A6)+OBUFFER40$:	LOAD.L	(A3),#-1	LOAD.L	A3,#(A6)+OBUFFER	LOAD.W	D3,(A6)+OSTEP	.W	SPLINE_OPEN	JUMP,NE	10$	CALL	DRAW	.W	SPLINE_CLOSE	JUMP	LOOP160$:	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	JUMP	LOOP1DRAW:	PUSHM.L	D2,D3,D4,A4	COMP.L	(A4),#-1	JUMP,EQ	90$10$:	COMP.L	(A4)+4,#-1	JUMP,EQ	90$	LOAD.L	D3,(A4)+0	; D3 <-- dpart (y;x)	LOAD.L	D4,(A4)+4	SUB.W	D4,D3		; D4 <-- longueur x	SWAP.W	D3	SWAP.W	D4	SUB.W	D4,D3		; D4 <-- longueur y	SWAP.W	D3	SWAP.W	D4	LOAD.W	D2,#INVDOT	.W	LIB,?DRSEG	ADD.L	A4,#4		; A4 <-- ^point suivant	JUMP	10$90$:	POPM.L	D2,D3,D4,A4	RETRETOUR:	.W	SPLINE_CLOSE	; fin d'ditionERFAT2:	LOAD.W	D1,(A6)+OCHSPLINE	.W	LIB_CLOSE	; ferme le module SPLINEERFAT1:	.W	LIB,?CLOLIB	; ferme la librairie	.W	FOS,?STOP	; c'est fini ...NAMSPLINE:.ASCIZ "SPLINE"	; nom du module LIB	.END	START